use std::collections::VecDeque;

struct MemoryBlock {
    address: u32,
    size: usize,
    is_writeable: bool,
}

fn process_memory_map(blocks: Vec<MemoryBlock>) -> (Vec<u32>, Vec<u32>) {
    let mut writable_addrs = Vec::new();
    let mut readonly_addrs = Vec::new();

    for block in blocks.into_iter() {
        if block.is_writeable {
            writable_addrs.push(block.address);
        } else {
            readonly_addrs.push(block.address);
        }
    }
    (writable_addrs, readonly_addrs)
}

fn main() {
    let blocks = vec![ 
        MemoryBlock { address: 0x40001000, size: 0x100, is_writeable: true }, 
        MemoryBlock { address: 0x3F400000, size: 0x80, is_writeable: false }, 
        MemoryBlock { address: 0x3F400040, size: 0x10, is_writeable: true }, 
        MemoryBlock { address: 0x3F401000, size: 0x20, is_writeable: false }, 
    ];

    let (writable, readonly) = process_memory_map(blocks);

    println!("Writes must happen at addresses: {:?}", writable);
    println!("Reads only from base addresses: {:?}", readonly);
}

use std::collections::HashMap;

#[derive(Clone)]
struct UserEvent {
    is_background: bool,
    event_type: String,
    data: u32,
}

fn process_events(events: Vec<UserEvent>) -> (Vec<String>, HashMap<String, i32>)
{
    let background_actions: Vec<String> = events.iter()
        .filter(|event| event.is_background)
        .map(|event| String::from(&event.event_type))
        .collect();

    let foreground_types: Vec<String> = events.iter()
        .filter(|event| !event.is_background)
        .map(|event| event.event_type.clone())
        .collect();

    let mut type_counts: HashMap<String, i32> = HashMap::new();

    for type_name in foreground_types.iter() {
        *type_counts.entry(type_name.clone()).or_insert(0) += 1;
    }

    (background_actions, type_counts)
}

use std::collections::{HashSet, HashMap};

struct Tile {
    x: usize,
    y: usize,
    is_solid: bool,
}

fn find_connected_components(all_tiles: &Vec<Tile>) -> HashMap<(usize, usize), Vec<(usize, usize)>> {
    let mut visited: HashSet<(usize, usize)> = HashSet::new();
    let mut components: HashMap<(usize, usize), Vec<(usize, usize)>> = HashMap::new();

    for tile in all_tiles.iter().filter(|t| t.is_solid) {
        if !visited.contains(&(tile.x, tile.y)) {
            let start_coord = (tile.x, tile.y);
            let mut stack: Vec<(usize, usize)> = vec![start_coord];
            let mut current_component: Vec<(usize, usize)> = Vec::new();
            visited.insert(start_coord);

            while let Some((cx, cy)) = stack.pop() {
                current_component.push((cx, cy));
                let neighbors = [(cx.wrapping_sub(1), cy), (cx + 1, cy), (cx, cy.wrapping_sub(1)), (cx, cy + 1)];

                for &(nx, ny) in &neighbors {
                    if nx < all_tiles.len() && ny < all_tiles.len()
                        && all_tiles.iter().any(|t| t.x == nx && t.y == ny && t.is_solid)
                        && !visited.contains(&(nx, ny)) 
                    {
                        visited.insert((nx, ny));
                        stack.push((nx, ny));
                    }
                }
            }
            components.insert(start_coord, current_component);
        }
    }
    components
}

pub fn main() {
    let tiles = vec![ 
        Tile { x: 0, y: 0, is_solid: true }, 
        Tile { x: 1, y: 0, is_solid: true }, 
        Tile { x: 2, y: 0, is_solid: false }, 
        Tile { x: 0, y: 1, is_solid: true }, 
        Tile { x: 1, y: 1, is_solid: true }, 
        Tile { x: 1, y: 2, is_solid: true }, 
    ];

    let solid_tiles: Vec<Tile> = tiles.into_iter().filter(|t| t.is_solid).collect();

    let components = find_connected_components(&solid_tiles);

    println!("Found {} distinct connected regions.", components.len());
}

use std::collections::HashMap;

struct UserEvent {
    service_id: String,
    timestamp: i64,
    data: HashMap<String, String>,
}

fn process_event_stream(events: Vec<UserEvent>) -> HashMap<String, Vec<UserEvent>> {
    let mut grouped_results: HashMap<String, Vec<UserEvent>> = HashMap::new();

    for event in events.into_iter().collect::<Vec<_>>().into_iter() {
        grouped_results.entry(event.service_id.clone()).or_default().push(event);
    }

    grouped_results
}

fn main() {
    let mut events = Vec::new();
    events.push(UserEvent { 
        service_id: "Auth".to_string(), 
        timestamp: 1678886400, 
        data: [("user_id".to_string(), "123".to_string())].iter().cloned().collect()
    });
    events.push(UserEvent { 
        service_id: "Analytics".to_string(), 
        timestamp: 1678886405, 
        data: [("event_type".to_string(), "view".to_string())].iter().cloned().collect()
    });
    events.push(UserEvent { 
        service_id: "Auth".to_string(), 
        timestamp: 1678886410, 
        data: [("status".to_string(), "success".to_string())].iter().cloned().collect()
    });

    let final_state = process_event_stream(events);

    for (service, events) in final_state.iter() {
        println!("Processed {} events for service: {}", events.len(), service);
    }
}
